function buildUniquePairs(pairs) {
  const seen = new Set();

  return pairs.filter(([source, target]) => {
    const key = `${source}=>${target}`;
    if (seen.has(key)) {
      return false;
    }

    seen.add(key);
    return true;
  });
}

export const TRANSLATION_PAIRS = buildUniquePairs(RAW_TRANSLATION_PAIRS);
